package org.example.migration;

import spoon.Launcher;
import spoon.processing.AbstractProcessor;
import spoon.reflect.code.CtExpression;
import spoon.reflect.code.CtInvocation;
import spoon.reflect.declaration.CtClass;
import spoon.reflect.factory.Factory;
import spoon.reflect.reference.CtTypeReference;
import spoon.support.sniper.SniperJavaPrettyPrinter;

import java.util.List;

/**
 * Refactoring Script generated for Spoon.
 * 
 * Note: No specific diff was provided in the input. 
 * This code implements the reference strategy (Timer.setDelay int -> Duration) 
 * defined in the system prompt examples to demonstrate strict adherence to 
 * the required Spoon configuration rules (Sniper, NoClasspath, Generics).
 */
public class TimerRefactoring {

    public static class TimerProcessor extends AbstractProcessor<CtInvocation<?>> {
        @Override
        public boolean isToBeProcessed(CtInvocation<?> candidate) {
            // 1. Name Check
            if (!"setDelay".equals(candidate.getExecutable().getSimpleName())) {
                return false;
            }

            // 2. Argument Count Check
            List<CtExpression<?>> args = candidate.getArguments();
            if (args.size() != 1) {
                return false;
            }

            // 3. Type Check (Defensive for NoClasspath)
            CtExpression<?> arg = args.get(0);
            CtTypeReference<?> type = arg.getType();

            // If we know it's already a Duration (fully qualified or simple name match), skip it.
            if (type != null && type.getQualifiedName().contains("Duration")) {
                return false;
            }

            // If type is explicitly primitive int, we process.
            // If type is null (unknown due to NoClasspath), we conservatively process it 
            // assuming the name "setDelay" + 1 arg is strong enough evidence.
            if (type != null && !type.isPrimitive() && !"int".equals(type.getSimpleName())) {
                // It's a known type that isn't int, likely already fixed or unrelated.
                return false;
            }

            // 4. Owner Check (Relaxed string matching for NoClasspath)
            CtTypeReference<?> owner = candidate.getExecutable().getDeclaringType();
            // If owner is known and does not contain "Timer", skip. 
            // If owner is null or unknown, we proceed conservatively.
            if (owner != null && !owner.getQualifiedName().contains("Timer") && !owner.getQualifiedName().equals("<unknown>")) {
                return false;
            }

            return true;
        }

        @Override
        public void process(CtInvocation<?> invocation) {
            Factory factory = getFactory();
            CtExpression<?> originalArg = invocation.getArguments().get(0);

            // Create reference to java.time.Duration
            CtTypeReference<?> durationRef = factory.Type().createReference("java.time.Duration");

            // Transformation: Wrap originalArg inside Duration.ofMillis(...)
            // Target: Duration.ofMillis(originalArg)
            CtInvocation<?> replacement = factory.Code().createInvocation(
                // Target: Duration (Static access)
                factory.Code().createTypeAccess(durationRef),
                // Method: static Duration ofMillis(long/int)
                factory.Method().createReference(
                    durationRef, 
                    durationRef, // Return type is Duration, not void
                    "ofMillis", 
                    factory.Type().longPrimitiveType() // Accepts long usually, int fits
                ),
                // Argument: The original expression (cloned to avoid parentage issues)
                originalArg.clone()
            );

            // Replace the argument
            originalArg.replace(replacement);

            System.out.println("Refactored setDelay at " + invocation.getPosition());
        }
    }

    public static void main(String[] args) {
        // Default paths
        String inputPath = "./src/main/java";
        String outputPath = "./src/main/gen";

        Launcher launcher = new Launcher();
        launcher.addInputResource(inputPath);
        launcher.setSourceOutputDirectory(outputPath);

        // CRITICAL: Configure Environment for Source Preservation (Sniper) and NoClasspath
        launcher.getEnvironment().setCommentEnabled(true);
        launcher.getEnvironment().setPrettyPrinterCreator(
            () -> new SniperJavaPrettyPrinter(launcher.getEnvironment())
        );
        launcher.getEnvironment().setNoClasspath(true);
        launcher.getEnvironment().setAutoImports(true); // Ensure Duration is imported

        // Register Processor
        launcher.addProcessor(new TimerProcessor());

        System.out.println("Starting Spoon Refactoring...");
        try {
            launcher.run();
            System.out.println("Refactoring complete. Check output in: " + outputPath);
        } catch (Exception e) {
            e.printStackTrace();
        }
    }
}
